var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐아아…. 배고파….","JPN":"ふええ……お腹空いた……","ENG":"Hnnngh... I'm hungry...","TWN":"呃呃呃…我好餓…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐. 먹을 거 없어요?","JPN":"ソーニャ。何か食べるものありませんか？","ENG":"Sonya. Do we have anything to eat?","TWN":"索妮雅，你有吃的嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"없어. 빈손으로 출발했으니까.","JPN":"ないよ。手ぶらで出発したから。","ENG":"Nope. We set sail with nothing.","TWN":"沒有，我們是二手空空出發的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그치만 아까부터 낚시하고 있잖아요.","JPN":"でもさっきから釣りしているじゃないですか。","ENG":"But you've been fishing for a while now.","TWN":"可是你剛剛不是在釣魚嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"틀렸어. 생선 한 마리도 잡히지 않아. 잡히는 곳인지도 모르겠고.","JPN":"ダメだ。魚が一匹も釣られない。そもそも魚がいるのかもわからないし。","ENG":"It won't work. I can't catch a single fish. I'm not even sure if there are fish here.","TWN":"只對一半，我一條魚都沒有釣到，也不知道能釣到魚嗎。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"검은 범람 때 이렇게 바다 깊숙이 나와본 적은 없으니까.","JPN":"黒い氾濫の時、こんなに海の遠くまで出たことはないから。","ENG":"I've never been this far out in the ocean during the Black Flood.","TWN":"我從來沒有在黑色洪災期間出海這麼遠過。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐아앙- 이대로 쫄쫄 굶어야 하다니, 말도 안 돼애.","JPN":"ふええーん、このままずっと何も食べられないなんて、あり得ないわ。","ENG":"Waaah! No way, I don't want to starve to death.","TWN":"嗚嗚嗚…還要繼續餓肚子嗎，好慘。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"크윽… 큭…","JPN":"くうっ……くっ……","ENG":"Kgh... Agh...","TWN":"咳…咳…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_WATER_06"},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님, 저희 얼마나 더 가야해요? 이러다 뙤약볕에 피부 다 상한다고요.","JPN":"船長、私たちいつになったら到着しますか？　このままだと日差しでお肌が丸焦げになってしまいますわ。","ENG":"How much longer will it take, Captain? All this sunlight is going to ruin my skin.","TWN":"船長，我們還要走多遠？繼續暴曬在烈日下會曬傷的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리. 그런 소리하면 못 써. 선장이 우릴 위해 애쓰고 있잖아.","JPN":"タリー。そんなこと言ったらダメだ。船長があたしたちのために頑張っているじゃないか。","ENG":"Tallie. Don't say that. Captain's trying her best to get us out of here.","TWN":"塔莉，你這樣說很不貼心，船長也很努力在想辦法。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님-! 힘내세요!","JPN":"船長ー！　頑張ってください！","ENG":"Go Captain! Wooo!","TWN":"船長！加油！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이 탈리는 선장님이 보트를 헤엄쳐서 끌 수 있는 A급 카운터라는 게 정말 자랑스럽답니다!","JPN":"このタリーは船長がボートを泳いで引っ張れるA級カウンターということが本当に誇らしいですわ！","ENG":"I'm so proud of you for being a Grade A Counter that can swim while dragging the whole boat with you!","TWN":"塔莉以船長為傲！竟然可以咬著繩子拖著船！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"소냐… 저 녀석 무거우니까… 생선 미끼로 던져버려…","JPN":"ソーニャ……あいつ重いから……魚のエサにしてやれ……","ENG":"Sonya... She's just adding to the weight... So just throw her overboard and use her as bait...","TWN":"索妮雅…這傢伙好重…把她扔去餵魚吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"…嗯？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님! 저기!","JPN":"船長！　あそこ！","ENG":"Captain! Over there!","TWN":"船長！看那邊！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"섬이 보이기 시작했어요!","JPN":"島が見えてきました！","ENG":"Land-ho! I see an island!","TWN":"我有看到一座小島！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"헤엑- 헥-","JPN":"はあーはあっー","ENG":"*Huff...* *Huff...*","TWN":"呼呼，呼呼。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"고생했어, 선장.","JPN":"ご苦労さま、船長。","ENG":"Good job, Captain.","TWN":"辛苦了，船長。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"끄응… 다리에 쥐가 다섯 번은 난 것 같아…","JPN":"ぐう……５回くらいは足がつった気がする……","ENG":"Ugh... I think I got a cramp in my leg like five times...","TWN":"呃…我的腿又開始抽筋了…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"에이, 무슨 섬이 이렇게 작아요? 이런 곳에서 먹을 거라도 구할 수 있으려나?","JPN":"もう、島が小さすぎではありませんか？　こんなところで食べ物を手に入れられるのでしょうか？","ENG":"Oh, what a small island. I wonder if we can even find food in a place like this.","TWN":"嘖，這算什麼島，小到連食物都找不到？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"평소에는 좀 더 큰 섬이겠지. 해수면이 높아지면서 봉우리만 남은 거야.","JPN":"普段はもっと大きかったんだろう。海水面が上昇して今は山の峰だけが残ったんだ。","ENG":"It's probably bigger at other times. The sea level rose and now we're seeing the peak of the island.","TWN":"正常情況下，這座島的面積應該更大才對，只是因為海平面上升，才會只剩下山峰。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님- 여긴 딱히 먹을 게 없는 거 같은데, 그냥 다른 섬 찾아보면 안 돼요?","JPN":"船長ー、ここは食べれる物がないようですが、他の島を探したらダメですか？","ENG":"Captaaain. There doesn't seem to be anything to eat here. Can we just look for a different island?","TWN":"船長，這裡似乎沒有食物，我們可以換一座島嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"저걸 바다로 던져버리고 싶은데… 팔에 힘이 없어…","JPN":"あいつを海に投げ捨てたいんだが……腕に力がない……","ENG":"I want to throw her into the ocean so bad... but my arms are out of strength...","TWN":"要不是我的手沒力，我真想把那傢伙扔進海裡…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"적어도 쉴 곳은 있으니, 선장이 기운을 차릴 때까지 숨 좀 돌리자.","JPN":"少なくとも休める場所はあるから、船長が元気になるまで少し休憩しよう。","ENG":"At least we can rest here. Let's take a breather until Captain recovers.","TWN":"至少我們有一個休息的地方，在船長恢復期間可以讓我們稍作休息。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으음… 어쩔 수 없네요.","JPN":"うーん……仕方ありません。","ENG":"Mmm... Okay.","TWN":"喔喔…也只能這樣囉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라…? 이 소리는…?","JPN":"あれ……？　今の音は……？","ENG":"Huh...? What's that sound...?","TWN":"嗯…？這聽起來像…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래. 누군가 곤경에 처한 것 같네.","JPN":"ああ。誰かが危険にさらされているようだ。","ENG":"Yeah. Sounds like someone's in danger.","TWN":"嗯嗯，似乎是有人遇到麻煩的樣子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"노획품을 챙길 기회란 뜻이네요! 얼른 가 봐요!","JPN":"戦利品を手に入れられるチャンスということですね！　さっさと行ってみましょう！","ENG":"That means we can get some loot! Let's go!","TWN":"這就表示我們有機會撈到戰利品囉！快去看看！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"야, 잠깐…!","JPN":"こら、ちょっと……！","ENG":"Hey, wait...!","TWN":"喂，你等等…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…기다리라고 해도 들을 리가 없지, 저 녀석.","JPN":"……待ってって言っても聞くはずないか、あいつ。","ENG":"...a second. Or not. Why do I even try?","TWN":"…你是攔不住她的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"잠깐 쉬고 있어, 선장. 금방 다녀올게.","JPN":"ちょっと休んでいろ、船長。すぐ戻ってくるから。","ENG":"Stay here and rest, Captain. We'll be back soon.","TWN":"船長，你留在這裡休息，我們馬上回來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"끄으응… 제기랄…","JPN":"うっ……くそ……","ENG":"Ngh... Damn it...","TWN":"呃…該死的…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};